INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (0.0, 2, 190801, 20033004, "2022/11/17 15:00:00", 20033, "報酬がもらえますよ！\nチェックしてみてください", 54, "2030/01/01 14:59:59", 2, 4, "カリン", -416.5, 0.0);
